export default function Throttle(callback, time) {
	let intervalId = -1;
	let stepped;
	let isDestroyed;
	let _callbackParam;

	this.destroy = function () {
		isDestroyed = true;

		if (intervalId !== -1) {
			clearInterval(intervalId);
			intervalId = -1;
		}

		callback = null;
	};

	this.step = function (callbackParam) {
		stepped = true;
		_callbackParam = callbackParam;

		if (intervalId === -1) {
			intervalId = setInterval(execute, time);
		}
	};

	function execute() {
		if (isDestroyed) {
			return;
		}

		if (!stepped) {
			clearInterval(intervalId);
			intervalId = -1;
		} else {
			callback(_callbackParam);

			stepped = false;
			_callbackParam = null;
		}
	}
}
