import React from "react";

import PortfolioItem from "./PortfolioItem";




import {ITEMS_DATA} from "./PortfolioItem";


export default function Portfolio() {
	return (
		<section id="Portfolio" className="content-width">
			<div className="content">
				<h1 className="section-header">Selected work</h1>

				<ul>{getItems()}</ul>
			</div>
			
		</section>
	);
}

function getItems() {
	return ITEMS_DATA.map((itemData) => <PortfolioItem key={itemData.title} data={itemData} />);
}

