import React, { Component } from "react";

import Home from "./components/Home";
import Portfolio from "./components/Portfolio";
import About from "./components/About";
import Contact from "./components/Contact";
// import SiteFooter from "./components/SiteFooter";
import NavBar from "./components/NavBar";
import Project from "./components/Project";
import AppSignals from "./logic/AppSignals";
import { PageNames } from "./logic/Constants";
import Navigation from "./logic/Navigation";
import AppModel from "./logic/AppModel";


new Navigation();

export default class App extends Component {
	constructor(props) {
		super(props);



		

		this.state = { pageId: AppModel.instance.pageId, sectionId:AppModel.instance.sectionId, projectId: AppModel.instance.projectId };
	}



	componentDidMount() {
		
		AppSignals.navigationChanged.add(this.onNavigationChanged);
	}

	onNavigationChanged = () => {
		
		const { pageId, sectionId, projectId } = AppModel.instance;

		this.setState({ pageId, sectionId, projectId });
	};

	render() {
		const { pageId, projectId } = this.state;
		
		
		let page =
			pageId === PageNames.project ? <Project projectId={projectId} /> : getHomePageContent();

		return <div id="App">{page}</div>;
	}
}

function getHomePageContent() {
	return (
		<React.Fragment>
			<NavBar/>
			<Home />			
			<Portfolio />
			<About />
			<Contact />
			{/* <SiteFooter/> */}
		</React.Fragment>
	);
}

