export default function Debounce(callback, time) {
	let timeoutId = -1;

	let isDestroyed;

	this.destroy = function () {
		isDestroyed = true;

		if (timeoutId !== -1) {
			clearTimeout(timeoutId);
		}

		callback = null;
	};

	this.step = function () {
		if (timeoutId === -1) {
			timeoutId = setTimeout(onTimeout, time);
		} else {
			clearTimeout(timeoutId);
			timeoutId = setTimeout(onTimeout, time);
		}
	};

	function onTimeout() {
		timeoutId = -1;

		if (isDestroyed) {
			return;
		}

		callback();
	}
}
