import React from "react";
import AppSignals from "../logic/AppSignals";
import {  LocationHashes } from "../logic/Constants";


import Vune from "./project-content/Vune";
import HyperWay from "./project-content/HyperWay";
import RandomDesigns from "./project-content/RandomDesigns";
import WhatsAppRedesigned from "./project-content/WhatsAppRedesigned";

/**
 * @props.projectId: a name from ProjectNames
 */
export default function Project(props) {
	
	window.scroll({ top: 0, left: 0, behavior: 'auto' });

	return (
		<div id="Project" className="content-width">
			<div className="NavBar">
				<div className="navbar-content content-width">
					<button className="back-btn" onClick={() => {
						
						AppSignals.backToPortfolioRequested.dispatch(props.projectId);
					}}>
						<span className="material-icons">arrow_back_ios</span>
						<span className="label">portfolio</span>
					</button>

					{/* <div className="title-container">
						<p>{PROJECT_NAMES[props.projectId]}</p>
					</div> */}
					
				</div>
			</div>

			{getProjectContent(props.projectId)}
		</div>
	);
}

function getProjectContent(projectId) {
	switch (projectId) {
		case LocationHashes.vune:
			return <Vune />;

		case LocationHashes.hyperway:
			return <HyperWay />;

		case LocationHashes.randomDesigns:
			return <RandomDesigns />;

		case LocationHashes.whatsappRedesigned:
			return <WhatsAppRedesigned />;

		default:
			return <React.Fragment />;
	}
}
