import AppModel from "./AppModel";
import AppSignals from "./AppSignals";
import { HOME_SECTIONS, LocationHashes, PageNames, PROJECT_IDS } from "./Constants";



export default class Navigation {
	constructor() {
		
		AppSignals.backToPortfolioRequested.add(this.onBackToPortfolioRequested);
		AppSignals.hashChangeRequested.add(this.onHashChangeRequested);
		AppSignals.portfolioItemSelected.add(this.onPortfolioItemSelected);
		AppSignals.aboutCardClicked.add(this.onAboutCardClicked);

		if (window.location.pathname !== '/') {
			window.location.pathname = '';
		}

		

		this.popstateListener();
	}

	startListeningToPopState() {
		window.addEventListener("popstate", this.popstateListener, false);
	}

	stoptListeningToPopState() {
		window.removeEventListener("popstate", this.popstateListener, false);
	}

	onBackToPortfolioRequested = (projectId) =>{

		AppModel.instance.pageId = PageNames.main;
		AppModel.instance.sectionId = LocationHashes.portfolio;
		AppModel.instance.projectId = projectId;

		this.onHashChangeRequested('');

		AppSignals.navigationChanged.dispatch();

		AppModel.instance.scrollsAfterUpdate = true;
	}

	onAboutCardClicked = () => {
		AppModel.instance.pageId = PageNames.main;
		AppModel.instance.sectionId = LocationHashes.about;
		AppModel.instance.projectId = '';


		this.onHashChangeRequested('');

		AppSignals.navigationChanged.dispatch();

		AppModel.instance.scrollsAfterUpdate = true;
	}

	onHashChangeRequested = (locationHash) =>{

		this.stoptListeningToPopState();
		window.location.hash = locationHash;
		this.startListeningToPopState();
	}

	onPortfolioItemSelected = (projectId) =>{

		AppModel.instance.pageId = PageNames.project;
		AppModel.instance.sectionId = '';
		AppModel.instance.projectId = projectId;

		this.onHashChangeRequested(projectId);

		AppSignals.navigationChanged.dispatch();
	}	

	popstateListener = () => {
		let hash = this.normalizeHash(window.location.hash);

		
		

		if (HOME_SECTIONS.includes(hash)){
			AppModel.instance.pageId = PageNames.main;
			AppModel.instance.sectionId = hash;
			AppModel.instance.projectId = '';

			AppModel.instance.scrollsAfterUpdate = true;

			this.onHashChangeRequested('');
		}
		else
		if (PROJECT_IDS.includes(hash)) {
			AppModel.instance.pageId = PageNames.project;
			AppModel.instance.sectionId = '';
			AppModel.instance.projectId = hash;
		}
		else{
			
			this.handle404();
			return;
		}

		AppSignals.navigationChanged.dispatch();
	}

	handle404(){
		
		AppModel.instance.pageId = PageNames.main;
		AppModel.instance.sectionId = LocationHashes.home;
		AppModel.instance.projectId = '';

		this.onHashChangeRequested('');

		AppSignals.navigationChanged.dispatch();
	}

	navigate(navRequest) {
		AppSignals.navigationApproved.dispatch(navRequest);
	}

	normalizeHash(hash) {
		return hash.replace("#", "").toLowerCase();
	}
}
