/**
 * Lightweight callback manager
 */
export default function Signal() {
	let listeners = [];
	let amount = 0;

	let stepping = false;

	let hasColdListeners = false;

	this.destroy = () => {
		for (let i = 0; i < listeners.length; i++) {
			listeners[i].callbackFunction = null;
		}

		listeners = null;
		amount = 0;
		stepping = false;
		hasColdListeners = false;
	};

	this.reset = () => {
		this.destroy();

		listeners = [];
	};

	this.add = (callback, removeOnFirstCallback = false, safeAdd = false) => {
		if (getListenerIndex(callback) > -1) {
			if (safeAdd) {
				return;
			}
			throw new Error("reregistered");
		}

		const listener = new SignalListener(callback);
		listener.removeOnFirstCallback = removeOnFirstCallback;

		listeners.push(listener);
		amount++;
	};

	this.remove = (callback, safeRemove = true) => {
		const index = getListenerIndex(callback);

		if (index === -1) {
			if (safeRemove) {
				return;
			} else {
				throw new Error("unregistered");
			}
		}

		if (stepping) {
			listeners[index].isCold = true;
			listeners[index].callbackFunction = null;

			hasColdListeners = true;
		} else {
			listeners.splice(index, 1);
			amount--;
		}
	};

	this.dispatch = (param = null) => {
		if (stepping) {
			throw new Error("stepping");
		}

		stepping = true;

		for (let i = 0; i < amount; i++) {
			const listener = listeners[i];

			if (listener.isCold) continue;

			if (listener.paramsRequired === 0) {
				listener.callbackFunction();
			} else if (listener.paramsRequired === 1) {
				listener.callbackFunction(param);
			} else if (listener.paramsRequired === 2) {
				listener.callbackFunction(this, param);
			}

			if (listener.removeOnFirstCallback) {
				listener.callbackFunction = null;
				listener.isCold = true;
				hasColdListeners = true;
			}
		}

		if (hasColdListeners) {
			for (let i = amount - 1; i > -1; i--) {
				if (listeners[i].isCold) {
					listeners.splice(i, 1);
					amount--;
				}
			}

			hasColdListeners = false;
		}

		stepping = false;
	};

	const getListenerIndex = (callback) => {
		for (let i = 0; i < amount; i++) {
			if (listeners[i].callbackFunction === callback) {
				return i;
			}
		}

		return -1;
	};
}

const SignalListener = function (callbackFunction) {
	this.callbackFunction = callbackFunction;

	this.removeOnFirstCallback = false;

	this.isCold = false;

	// 0:none, 1:param, 2:signal and param
	this.paramsRequired = callbackFunction.length;
};
