import React from "react";
import AppSignals from "../logic/AppSignals";
import { LocationHashes } from "../logic/Constants";


export const ITEMS_DATA = [
	{
		id: LocationHashes.vune,
		title: "Vune",
		caption: `Taking group chats to the next level`,
		featured: true,
		img: "vune/portfolio-item-cover.png",
		color: "#e64e99"
	},
	{
		id: LocationHashes.hyperway,
		title: "HyperWay",
		caption: `The high-speed, urban transportation system of the future`,
		img: "hyperway/portfolio-item-cover.png",
		color: '#32e0bb'
	},
	{
		id: LocationHashes.randomDesigns,
		title: "Random Designs",
		caption: `"The details are not the details.
		They make the design"`,
		img: "random-designs/portfolio-item-cover.png",
		color: '#e6983b'
	},
	{
		id: LocationHashes.whatsappRedesigned,
		title: "WhatsApp Redesigned",
		caption: `"Wow, thanks man, looks awesome!!"
		-Some guy on reddit`,
		img: "whatsapp/portfolio-item-cover.png",
		color: '#41c573'
	},
];

Object.freeze(ITEMS_DATA);


export default function PortfolioItem(props) {

	const data = props.data ? props.data : getItemData(props.name);

	const buttonShadowStyle = {boxShadow: "5px 5px " + data.color};

	return (
		<li className="PortfolioItem" id={data.id}>
			{/* {props.data.featured && <FeaturedVector />} */}

			<div className="text-container">
				<p className="title">{data.title}</p>
				<p className="caption">{data.caption}</p>
				<button style={buttonShadowStyle}
					onClick={() => {
						
						AppSignals.portfolioItemSelected
							.dispatch(data.id);
					}}
				>
					View
				</button>
			</div>

			<div className="image-container">
				<img src={data.img} alt="Project cover" />
			</div>
		</li>
	);
}

export function getItemData(itemId){

	if (!itemId) {
        throw new Error('expected name. got:' + itemId);
	}

	for(let i = 0; i < ITEMS_DATA.length; i++){

		if (ITEMS_DATA[i].id === itemId) {
			return ITEMS_DATA[i];
		}
	}

	return null;
}