
import {PageNames, LocationHashes} from "./Constants";

let _instance;

export default class AppModel{

	constructor(){

		this.pageId = PageNames.main;
		this.sectionId = LocationHashes.home;
		this.projectId = '';
		this.scrollsAfterUpdate = false;

		_instance = this;
	}

	static get instance() {

		if (!_instance) {
			_instance = new AppModel();
		}

		return _instance;
	}
}