import React, { Component } from "react";
import Throttle from "../utils/Throttle";
import Debounce from "../utils/Debounce";


import { LocationHashes, NAV_BAR_HEIGHT, PROJECT_IDS } from "../logic/Constants";
import AppModel from "../logic/AppModel";

export default class NavBar extends Component {
	constructor(props) {
		super(props);

		this.state = {
			currentSection: props.sectionId || '',
		};

		this.scrollListenerBlocked = false;

		this.isDestroyed = false;
	}

	componentWillUnmount() {
		this.isDestroyed = true;
		window.removeEventListener("scroll", this.scrollListener);
		

		this.updateHashThrottle.destroy();
		this.scrollBlockDebouncer.destroy();

		this.updateHashThrottle = null;
		this.scrollBlockDebouncer = null;
	}

	componentDidMount() {
		window.addEventListener("scroll", this.scrollListener);

		this.updateHashThrottle = new Throttle(this.updateHash, 250);
		this.scrollBlockDebouncer = new Debounce(this.unlockScrollListener, 2000);

		
		
		
		if (AppModel.instance.scrollsAfterUpdate) {

			AppModel.instance.scrollsAfterUpdate = false;

			if (AppModel.instance.projectId !== '') {
				this.scrollTo(AppModel.instance.projectId, true)
			}
			else{
				this.scrollTo(AppModel.instance.sectionId, true)
			}
			
		}
	}

	componentDidUpdate (){
		

		if (AppModel.instance.scrollsAfterUpdate) {

			AppModel.instance.scrollsAfterUpdate = false;
			
			this.scrollTo(AppModel.instance.sectionId, true)
		}
	}


	scrollListener = () => {
		if (this.scrollListenerBlocked) {
			return;
		}

		this.updateHashThrottle.step();
	};

	unlockScrollListener = () => {
		this.scrollListenerBlocked = false;
	};

	updateHash = () => {
		if (this.isDestroyed) {
			return;
		}

		let hash = "";
		let home = document.querySelector("#Home");
		let portfolio = document.querySelector("#Portfolio");
		let about = document.querySelector("#About");
		let contact = document.querySelector("#Contact");
		let sections = [home, portfolio, about, contact];

		let sectionUnderCenter;

		for (let i = 0; i < sections.length; i++) {
			if (isSectionUnderCenter(sections[i])) {
				sectionUnderCenter = sections[i];
				break;
			}
		}

		hash = sectionUnderCenter ? sectionUnderCenter.id.toLowerCase() : "";

		if (this.state.currentSection !== hash) {
			this.setState({ currentSection: hash });
		}
	};

	scrollTo = (target, fromEvent) => {
		let id;
		
		switch (target) {
			case LocationHashes.portfolio:
				id = "Portfolio";
				break;
			case LocationHashes.about:
				id = "About";
				break;
			case LocationHashes.contact:
				id = "Contact";
				break;

			default:
				if (PROJECT_IDS.includes(target)) {
					id = target;
				}
				else{
					return;
				}
				
		}

		let section = document.querySelector("#" + id);
		
		if (section) {
			let behavior = fromEvent ? "auto" : "smooth";

			this.setState({ currentSection: target });
			this.scrollListenerBlocked = true;

			

			let scrollTargetY = section.offsetTop - NAV_BAR_HEIGHT;

			if (PROJECT_IDS.includes(target)) {
				scrollTargetY = section.offsetTop + section.offsetHeight / 2 - window.innerHeight / 2;
			}
			
			
			
			// IMPORTANT: scroll() won't work if it has a comma before '}'
			window.scroll({ top: scrollTargetY, left: 0, behavior: behavior });

			this.scrollBlockDebouncer.step();
		}
	};

	render() {
		let currentSection = this.state.currentSection;

		

		return (
			<div className="NavBar">
				<div className="navbar-content content-width">

					<button className="logo-name" title="Back to top"
					onClick={() => {
						window.scroll({ top: 0, left: 0, behavior: 'smooth' })
					}}>Ivan Cass</button>

					<button
						className={getClassName(LocationHashes.portfolio, currentSection)}
						onClick={() => this.scrollTo(LocationHashes.portfolio)}
					>
						{LocationHashes.portfolio}
					</button>

					<button
						className={getClassName(LocationHashes.about, currentSection)}
						onClick={() => this.scrollTo(LocationHashes.about)}
					>
						{LocationHashes.about}
					</button>

					<button
						className={getClassName(LocationHashes.contact, currentSection)}
						onClick={() => this.scrollTo(LocationHashes.contact)}
					>
						{LocationHashes.contact}
					</button>
				</div>
			</div>
		);
	}
}

function isSectionUnderCenter(el) {
	let windowCenter = (window.innerHeight || document.documentElement.clientHeight) / 2;
	var rect = el.getBoundingClientRect();

	return windowCenter >= rect.top && windowCenter <= rect.bottom;
}

function getClassName(label, currentSection) {
	if (label.toLowerCase() === currentSection.toLowerCase()) {
		return "selected";
	}
	return "";
}
