import React from "react";
import Lightbox from "./Lightbox";

/**
 * @src: img attribute
 * @alt: img attribute
 * @isMobile: if true, there's no zoom and drag
 * @width: img attribute
 * @height: img attribute
 * @id: img attribute (optional)
 * @classes: img attribute (optional)
 */
export default function LightBoxImg(props) {
	let altText = props.alt === null ? "Image has no description" : props.alt;

	return (
		<img
			src={props.src}
			className={props.classes}
			id={props.id}
			width={props.width}
			height={props.height}
			loading="lazy"
			title="Click to view"
			alt={altText}
			onClick={() => new Lightbox(props.src, props.isMobile)}
			style={{ cursor: "pointer" }}
		/>
	);
}
