/**
 * Lightweight image viewer with zoom and drag (only for web).
 * @src: the full size image source.
 *
 * test with:
 * let url = "https://i.redd.it/un216px8jmc51.jpg";
 * new Lightbox(url, false)
 *
 * v0.12
 */
export default function Lightbox(src, isMobile = false) {
	// image can be zoomed up to 300%
	const max_scale = 3;

	// each zoom step scales 50%
	const factor = 0.5;

	// we record the original size, to use in calculations
	let size;

	// the image's position is calculated on this object, then applied to the image
	let pos = { x: 0, y: 0 };

	// these are used to zoom relative to the cursor
	let zoomTarget = { x: 0, y: 0 };
	let zoomPoint = { x: 0, y: 0 };

	let scale = 1;

	const fadeAnimDurationMs = 300;

	// these are used to drag the image
	let clientX;
	let clientY;
	let dragOffsetX;
	let dragOffsetY;

	let inputLocked = false;
	let resizeLockTimeoutId = -1;

	let isDestroyed = false;
	let isDestroying = false;

	let container, img, closeIcon, closeButton;
	let self = this;

	createElements();

	this.destroy = () => {
		if (isDestroyed) {
			return;
		}

		// first animate a fade out, then really destroy
		if (!isDestroying) {
			window.removeEventListener("resize", windowResizeListener);
			container.removeEventListener("click", containerClickListener);
			container.removeEventListener("mousedown", mouseDownListener);
			container.removeEventListener("mouseup", mouseUpListener);
			container.removeEventListener("mouseleave", mouseUpListener);
			container.removeEventListener("wheel", mouseWheelListener);
			container.removeEventListener("mousemove", mouseMoveListener, false);

			isDestroying = true;
			container.style.opacity = 0;

			setTimeout(self.destroy, fadeAnimDurationMs);
			return;
		}

		document.body.style.overflowY = "auto";

		if (container.parentElement) {
			container.parentElement.removeChild(container);
		}

		img.removeEventListener("load", init);

		container = img = closeIcon = closeButton = self = null;
		isDestroyed = true;
	};

	function createElements() {
		container = document.createElement("div");
		container.id = "Lightbox";
		container.style.width = "100vw";
		container.style.height = "100vh";
		container.style.position = "fixed";
		container.style.backgroundColor = "rgb(16 16 16 / 90%)";
		container.style.top = "0";
		container.style.left = "0";
		container.style.zIndex = "10";
		container.style.opacity = 0;
		container.style.transition = "opacity " + fadeAnimDurationMs + "ms";
		container.addEventListener("click", containerClickListener, false);

		img = document.createElement("img");
		img.addEventListener("load", init, false);
		img.addEventListener("error", onImageError, false);
		img.src = src;
		img.draggable = true;
		img.style.transformOrigin = "0 0";
		img.style.position = "relative";

		closeIcon = document.createElement("span");
		closeIcon.innerHTML = "&#x2715;";
		// bold X
		// closeIcon.innerHTML = "&#x2716;";
		closeIcon.style.color = "white";
		closeIcon.style.fontSize = "20px";
		closeIcon.style.position = "relative";
		closeIcon.style.top = "-2px";
		closeIcon.style.left = "1px";

		closeButton = document.createElement("button");
		closeButton.id = 'lightbox-close-btn';
		closeButton.style.backgroundColor = "rgb(58 58 58)";
		closeButton.style.width = "40px";
		closeButton.style.height = "40px";
		closeButton.style.borderRadius = "50%";
		closeButton.style.position = "absolute";
		closeButton.style.top = "15px";
		closeButton.style.right = "15px";
		closeButton.style.display = "flex";
		closeButton.style.justifyContent = "center";
		closeButton.style.alignItems = "center";
		closeButton.title = "Close";

		container.appendChild(img);
		closeButton.appendChild(closeIcon);
		container.appendChild(closeButton);
		document.body.appendChild(container);

		setTimeout(() => {
			if (container) {
				container.style.opacity = 1;
			}
		}, 10);
	}

	function onImageError(e) {
		if (isDestroyed) {
			return;
		}

		img.style.display = "none";

		let message = document.createElement("p");
		message.innerText = "Oops! Couldn't load your image.";
		message.style.color = "grey";
		message.style.margin = 0;

		container.style.display = "flex";
		container.style.justifyContent = "center";
		container.style.alignItems = "center";

		container.appendChild(message);

		document.body.style.overflowY = "hidden";
	}

	function containerClickListener(e) {
		if (inputLocked) {
			return;
		}

		switch (e.target) {
			case container:
			case closeIcon:
			case closeButton:
				self.destroy();
				break;
			default:
		}
	}

	function init() {
		if (isDestroyed) {
			return;
		}

		size = { w: img.width, h: img.height };
		Object.freeze(size);

		resizeAndCenter();

		if (!isMobile) {
			container.addEventListener("mousedown", mouseDownListener, false);
			container.addEventListener("mouseup", mouseUpListener, false);
			container.addEventListener("mouseleave", mouseUpListener, false);

			// use wheel instead of mousewheel (because of firefox)
			container.addEventListener("wheel", mouseWheelListener, false);

			enableImgTransition(false);
		}

		window.addEventListener("resize", windowResizeListener);

		document.body.style.overflowY = "hidden";
	}

	/**
	 * When the viewer is opened, after resizeAndCenter(), the transition needs to be set with a
	 * delay, otherwise it animates.
	 */
	function enableImgTransition(immediate) {
		if (immediate) {
			if (img) {
				img.style.transition = "transform .3s";
			}
		} else {
			setTimeout(() => {
				enableImgTransition(true);
			}, 100);
		}
	}

	/**
	 * the initial resize and center needs to be immediate, without animations. the same for
	 * dragging
	 */
	function disableImgTransition() {
		img.style.transition = "unset";
	}

	function resizeAndCenter() {
		fitScaleToViewport();

		if (scale > 1) {
			scale = 1;
		}

		pos.x = container.clientWidth / 2 - (size.w * scale) / 2;
		pos.y = container.clientHeight / 2 - (size.h * scale) / 2;

		update();
	}

	function fitScaleToViewport() {
		// if the width of the image is larger than its height
		if (size.w > size.h) {
			/**
			 * get the scale it needs from the relationship between the screen's width and the
			 * original image width
			 */
			scale = container.clientWidth / size.w;

			/**
			 * if using that scale means the height of the image would end up being larger than
			 * the screen's height, get the scale from the relationship of heights instead of widths
			 */
			if (size.h * scale > container.clientHeight) {
				scale = container.clientHeight / size.h;
			}
		} else {
			scale = container.clientHeight / size.h;

			if (size.w * scale > container.clientWidth) {
				scale = container.clientWidth / size.w;
			}
		}
	}

	/**
	 * debunce resizeAndCenter()
	 */
	function windowResizeListener() {
		if (isDestroyed || isDestroying) {
			return;
		}

		inputLocked = true;

		if (resizeLockTimeoutId !== -1) {
			clearTimeout(resizeLockTimeoutId);
		}

		resizeLockTimeoutId = setTimeout(() => {
			disableImgTransition();

			resizeAndCenter();

			enableImgTransition();

			inputLocked = false;
			resizeLockTimeoutId = -1;
		}, 100);
	}

	function mouseDownListener(e) {
		if (inputLocked) {
			return;
		}

		if (!isMobile) {
			e.preventDefault();
		}

		if (e.target !== img) {
			return;
		}

		if (!isMobile) {
			// set up the data we're going to need in mousemove
			setClientCoords(e);
			setDragOffset();

			container.addEventListener("mousemove", mouseMoveListener, false);
		}

		disableImgTransition();
	}

	function mouseUpListener(e) {
		if (!isMobile) {
			container.removeEventListener("mousemove", mouseMoveListener, false);
		}

		enableImgTransition(true);
	}

	function mouseWheelListener(e) {
		if (inputLocked) {
			return;
		}

		e.preventDefault();

		let direction = 1;

		if (e.deltaY > 0) {
			direction *= -1;
		}

		zoom(e, direction);
	}

	/**
	 * Image dragging
	 */
	function mouseMoveListener(e) {
		if (inputLocked) {
			return;
		}

		e.preventDefault();

		// block dragging if the image is smaller than the window and its bounds are inside the window
		if (
			(size.w * scale <= container.clientWidth || size.h * scale <= container.clientHeight) &&
			pos.x >= 0 &&
			pos.x + size.w * scale <= container.clientWidth &&
			pos.y >= 0 &&
			pos.y + size.h * scale <= container.clientHeight
		) {
			return;
		}

		setClientCoords(e);

		// the image's position is the cursor location minus the offset determined on mouseDown
		pos.x = clientX - dragOffsetX;
		pos.y = clientY - dragOffsetY;

		update();
	}

	function zoom(e, direction, forcedScale = null) {
		zoomPoint.x = e.clientX - img.offsetLeft;
		zoomPoint.y = e.clientY - img.offsetTop;

		// determine the point where the img is zoomed in
		zoomTarget.x = (zoomPoint.x - pos.x) / scale;
		zoomTarget.y = (zoomPoint.y - pos.y) / scale;

		scale += direction * factor * scale;

		if (scale > max_scale) {
			scale = max_scale;
		}

		if (scale < 1) {
			// if the viewport is smaller than the original image size, allow scales smaller than 1
			if (container.clientWidth < size.w || container.clientHeight < size.h) {
				// if we're zooming out and the image is smaller than the window
				if (
					direction === -1 &&
					size.w * scale < container.clientWidth &&
					size.h * scale < container.clientHeight
				) {
					fitScaleToViewport();
				}
			} else {
				scale = 1;
			}
		}

		if (forcedScale !== null) {
			scale = forcedScale;
		}

		// move the img so that we zoom into the cursor's position
		pos.x = -zoomTarget.x * scale + zoomPoint.x;
		pos.y = -zoomTarget.y * scale + zoomPoint.y;

		// if zooming out, and the img is smaller than the screen, center the img
		if (
			direction === -1 &&
			size.w * scale <= container.clientWidth &&
			size.h * scale <= container.clientHeight
		) {
			pos.x = container.clientWidth / 2 - (size.w * scale) / 2;
			pos.y = container.clientHeight / 2 - (size.h * scale) / 2;
		}

		update();
	}

	/**
	 * Using "toFixed" to prevent image blurring (which happens when position is decimal)
	 */
	function update() {
		img.style.transform =
			"translate(" + pos.x.toFixed(0) + "px," + pos.y.toFixed(0) + "px) scale(" + scale + "," + scale + ")";
	}

	/**
	 * Where the cursor is relative to the image position.
	 */
	function setDragOffset() {
		var rect = img.getBoundingClientRect();

		dragOffsetX = clientX - rect.x;
		dragOffsetY = clientY - rect.y;
	}

	/**
	 * How far we are from the document's left/top.
	 */
	function setClientCoords(e) {
		// don't use 'isMobile' to check, because e.touches may be unavailable
		if (e.touches) {
			clientX = e.touches[0].clientX;
			clientY = e.touches[0].clientY;
		} else {
			clientX = e.clientX;
			clientY = e.clientY;
		}
	}
}
